import { Avatar, Card, CardActionArea, CardContent, CardHeader, Divider, IconButton, Typography } from '@material-ui/core'
import { MoreVert } from '@material-ui/icons'
import { makeStyles } from '@material-ui/styles'
import React from 'react'

const useStyle = makeStyles(theme => {
  return {
    root: {
      // '& .MuiCard-root:hover': {
        // boxShadow: 'none',
        // background: 'none'
    },
    avatar: {
      background: '#162276'
    },
    moreIcon: {
      zIndex: 1
    }
  
  }
})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
      <Card elevation={1}>
        <CardActionArea>
          <CardHeader
            avatar={
              <Avatar className={classes.avatar}>
                P
              </Avatar>
            }
            action={
              <IconButton className={classes.moreIcon}>
                <MoreVert />
              </IconButton>
            }
            title={subject.title}
            subheader={subject.instructor}
            zIndex = {1}
          />
          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
        </CardActionArea>
      </Card>
    </div>
  )
}
